# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import NoBrokersAvailable, TopicAlreadyExistsError, UnknownTopicOrPartitionError

def create_topic(admin_client, topic_name, num_partitions, replication_factor, topic_configs):
    print(f"Attempting to create topic: {topic_name} with {num_partitions} partitions, replication factor {replication_factor}, and configs {topic_configs}")
    try:
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs if topic_configs else None
        )
        admin_client.create_topics(new_topics=[new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully.")
    except TopicAlreadyExistsError:
        print(f"Topic '{topic_name}' already exists.")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def delete_topic(admin_client, topic_name):
    print(f"Attempting to delete topic: {topic_name}")
    try:
        admin_client.delete_topics(topics=[topic_name])
        print(f"Topic '{topic_name}' deleted successfully.")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' does not exist.")
    except Exception as e:
        print(f"Error deleting topic '{topic_name}': {e}")

def alter_topic_partitions(admin_client, topic_name, new_num_partitions):
    print(f"Attempting to alter partitions for topic: {topic_name} to {new_num_partitions}")
    try:
        # Get current topic metadata to check if partitions need to be increased
        topic_metadata = admin_client.describe_topics(topics=[topic_name])
        current_partitions = topic_metadata[0].num_partitions

        if new_num_partitions <= current_partitions:
            print(f"Cannot decrease or keep the same number of partitions. Current: {current_partitions}, Requested: {new_num_partitions}")
            return

        admin_client.alter_configs(
            config_resources=[
                ConfigResource(
                    resource_type=ConfigResourceType.TOPIC,
                    resource_name=topic_name,
                    configs={'num.partitions': str(new_num_partitions)}
                )
            ]
        )
        print(f"Successfully initiated partition increase for topic '{topic_name}' to {new_num_partitions}.")
        print("Note: Partition increases are asynchronous and might take some time to reflect.")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' does not exist.")
    except Exception as e:
        print(f"Error altering partitions for topic '{topic_name}': {e}")

def describe_topic(admin_client, topic_name):
    print(f"Describing topic: {topic_name}")
    try:
        topic_metadata = admin_client.describe_topics(topics=[topic_name])
        if topic_metadata:
            for tm in topic_metadata:
                print(f"\nTopic Name: {tm.name}")
                print(f"  Partitions: {tm.num_partitions}")
                print(f"  Replication Factor: {tm.replication_factor}")
                print(f"  Is Internal: {tm.is_internal}")
                print("  Partitions Details:")
                for partition_id, partition_info in tm.partitions.items():
                    print(f"    Partition {partition_id}:")
                    print(f"      Leader: {partition_info.leader}")
                    print(f"      Replicas: {partition_info.replicas}")
                    print(f"      ISR: {partition_info.isr}")
        else:
            print(f"Topic '{topic_name}' not found.")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' does not exist.")
    except Exception as e:
        print(f"Error describing topic '{topic_name}': {e}")

def describe_topic_configs(admin_client, topic_name):
    print(f"Describing configurations for topic: {topic_name}")
    try:
        config_resources = admin_client.describe_configs(
            config_resources=[
                ConfigResource(ConfigResourceType.TOPIC, topic_name)
            ]
        )
        if config_resources:
            for resource in config_resources:
                print(f"\nResource Name: {resource.resource_name}, Type: {resource.resource_type}")
                for config_entry in resource.configs:
                    print(f"  {config_entry.name}: {config_entry.value} (Source: {config_entry.config_source.name}, Read-only: {config_entry.read_only}, Sensitive: {config_entry.is_sensitive}, Default: {config_entry.is_default})")
        else:
            print(f"No configurations found for topic '{topic_name}'.")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' does not exist.")
    except Exception as e:
        print(f"Error describing topic configurations for '{topic_name}': {e}")

def alter_topic_configs(admin_client, topic_name, topic_configs):
    if not topic_configs:
        print("No configurations provided to alter.")
        return

    print(f"Attempting to alter configurations for topic: {topic_name} with configs: {topic_configs}")
    try:
        config_resource = ConfigResource(
            resource_type=ConfigResourceType.TOPIC,
            resource_name=topic_name,
            configs=topic_configs
        )
        admin_client.alter_configs(config_resources=[config_resource])
        print(f"Configurations for topic '{topic_name}' altered successfully.")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' does not exist.")
    except Exception as e:
        print(f"Error altering configurations for topic '{topic_name}': {e}")

def list_topics(admin_client):
    print("Listing all topics:")
    try:
        topics = admin_client.list_topics()
        if topics:
            for topic in sorted(topics):
                print(f"- {topic}")
        else:
            print("No topics found.")
    except Exception as e:
        print(f"Error listing topics: {e}")

def parse_key_value_pairs(items):
    """Parses a list of 'key=value' strings into a dictionary."""
    if not items:
        return {}
    parsed_dict = {}
    for item in items:
        if '=' in item:
            key, value = item.split('=', 1)
            parsed_dict[key] = value
        else:
            print(f"Warning: Skipping malformed config '{item}'. Expected 'key=value'.")
    return parsed_dict

def main():
    parser = argparse.ArgumentParser(description="Kafka Topic Administration Script using kafka-python AdminClient.")
    parser.add_argument('--bootstrap-servers', default='localhost:9092',
                        help='Comma-separated list of Kafka bootstrap servers.')

    subparsers = parser.add_subparsers(dest='command', help='Available commands', required=True)

    # Create Topic command
    create_parser = subparsers.add_parser('create', help='Create a new Kafka topic.')
    create_parser.add_argument('--topic', required=True, help='Name of the topic to create.')
    create_parser.add_argument('--partitions', type=int, default=1, help='Number of partitions for the topic.')
    create_parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor for the topic.')
    create_parser.add_argument('--config', nargs='*', help='Topic configuration in key=value format (e.g., retention.ms=604800000).')

    # Delete Topic command
    delete_parser = subparsers.add_parser('delete', help='Delete an existing Kafka topic.')
    delete_parser.add_argument('--topic', required=True, help='Name of the topic to delete.')

    # Alter Partitions command
    alter_partitions_parser = subparsers.add_parser('alter-partitions', help='Alter the number of partitions for a topic (can only increase).')
    alter_partitions_parser.add_argument('--topic', required=True, help='Name of the topic to alter.')
    alter_partitions_parser.add_argument('--new-partitions', type=int, required=True, help='New number of partitions.')

    # Describe Topic command
    describe_parser = subparsers.add_parser('describe', help='Describe a Kafka topic (metadata).')
    describe_parser.add_argument('--topic', required=True, help='Name of the topic to describe.')

    # Describe Topic Configs command
    describe_configs_parser = subparsers.add_parser('describe-configs', help='Describe configurations for a Kafka topic.')
    describe_configs_parser.add_argument('--topic', required=True, help='Name of the topic to describe configurations for.')

    # Alter Topic Configs command
    alter_configs_parser = subparsers.add_parser('alter-configs', help='Alter configurations for a Kafka topic.')
    alter_configs_parser.add_argument('--topic', required=True, help='Name of the topic to alter configurations for.')
    alter_configs_parser.add_argument('--config', nargs='*', required=True, help='Topic configuration in key=value format to alter (e.g., retention.ms=604800000).')

    # List Topics command
    list_parser = subparsers.add_parser('list', help='List all Kafka topics.')

    args = parser.parse_args()

    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=args.bootstrap_servers,
            client_id='kafka-admin-script'
        )
        print(f"Connected to Kafka bootstrap servers: {args.bootstrap_servers}")
    except NoBrokersAvailable:
        print(f"Error: No Kafka brokers available at {args.bootstrap_servers}")
        return
    except Exception as e:
        print(f"Failed to connect to Kafka: {e}")
        return

    try:
        if args.command == 'create':
            topic_configs = parse_key_value_pairs(args.config)
            create_topic(admin_client, args.topic, args.partitions, args.replication_factor, topic_configs)
        elif args.command == 'delete':
            delete_topic(admin_client, args.topic)
        elif args.command == 'alter-partitions':
            alter_topic_partitions(admin_client, args.topic, args.new_partitions)
        elif args.command == 'describe':
            describe_topic(admin_client, args.topic)
        elif args.command == 'describe-configs':
            describe_topic_configs(admin_client, args.topic)
        elif args.command == 'alter-configs':
            topic_configs = parse_key_value_pairs(args.config)
            alter_topic_configs(admin_client, args.topic, topic_configs)
        elif args.command == 'list':
            list_topics(admin_client)
    finally:
        admin_client.close()
        print("Admin client closed.")

if __name__ == '__main__':
    main()